import { Component, inject, OnInit, ChangeDetectorRef } from '@angular/core';
import { FormsModule } from '@angular/forms';

@Component({
  selector: 'app-profile-settings',
  standalone: true,
  imports: [FormsModule], // 🚀 Nettoyé : NgIf a été retiré pour effacer le warning
  templateUrl: './profile-settings.component.html',
  styles: [`
    .profile-container { max-width: 800px; margin: 0 auto; padding-top: 10px; }
    .profile-card { background: #ffffff; border-radius: 12px; border: 1px solid #e2e8f0; padding: 30px; }
    .card-header { margin-bottom: 25px; border-bottom: 1px solid #f1f5f9; padding-bottom: 15px; }
    .card-header h3 { margin: 0 0 6px 0; color: #0f172a; font-size: 20px; font-weight: 700; display: flex; align-items: center; gap: 10px; }
    .card-header p { margin: 0; color: #64748b; font-size: 14px; }
    .logo-upload-section { display: flex; align-items: center; gap: 24px; background-color: #f8fafc; padding: 20px; border-radius: 8px; margin-bottom: 25px; }
    .logo-preview { width: 100px; height: 100px; border-radius: 8px; border: 2px solid #e2e8f0; background: #fff; overflow: hidden; display: flex; justify-content: center; align-items: center; }
    .logo-preview img { width: 100%; height: 100%; object-fit: cover; }
    .btn-secondary-upload { background-color: #ffffff; border: 1px solid #cbd5e1; color: #334155; padding: 8px 16px; border-radius: 6px; font-size: 13px; font-weight: 600; cursor: pointer; }
    .form-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 20px; }
    .form-group { display: flex; flex-direction: column; gap: 6px; }
    .form-group label { font-size: 13px; font-weight: 600; color: #334155; }
    .form-group input, .form-group textarea { width: 100%; padding: 10px 14px; border: 1px solid #cbd5e1; border-radius: 6px; font-size: 14px; }
    .url-group { grid-column: span 2; }
    .btn-save { background-color: #0ea5e9; color: white; border: none; border-radius: 6px; padding: 12px 24px; font-size: 14px; font-weight: 600; cursor: pointer; margin-top: 25px; width: 100%; }
    .alert-box { padding: 12px; border-radius: 6px; margin-bottom: 20px; font-size: 14px; text-align: center; }
    .alert-success { background-color: #e6f4ea; color: #137333; border: 1px solid #ceead6; }
  `]
})
export class ProfileSettingsComponent implements OnInit {
  private cdr = inject(ChangeDetectorRef);

  profile = { company_name: '', phone: '', address: '', company_bio: '' };
  logoPreviewUrl: string | null = null;
  successMessage = '';

  ngOnInit() {
    this.profile.company_name = localStorage.getItem('name') || 'Mon Entreprise';
  }

  onFileSelected(event: any) {
    const file = event.target.files[0]; // 🔍 Sécurisé : Extraction directe du fichier
    if (file) {
      const reader = new FileReader();
      reader.onload = () => {
        this.logoPreviewUrl = reader.result as string;
        this.cdr.detectChanges();
      };
      reader.readAsDataURL(file);
    }
  }

  onSaveProfile(event: Event) {
    event.preventDefault();
    localStorage.setItem('name', this.profile.company_name);
    this.successMessage = "Les informations de votre profil et votre logo ont été mis à jour.";
    this.cdr.detectChanges();

    setTimeout(() => {
      this.successMessage = '';
      this.cdr.detectChanges();
    }, 3000);
  }
}
